#include <bits/stdc++.h>
using namespace std;
long long n,m,r[1000006],d[1000006],s[1000006],t[1000006];
bool check(long long mid){
    long long c[1000006],sum[1000006];
    memset(c,0,sizeof(c));
    for(long long i=1;i<=mid;i++)c[s[i]]+=d[i],c[t[i]+1]-=d[i];
    sum[0]=0;
    for(long long i=1;i<=n;i++){
        sum[i]=sum[i-1]+c[i];
        if(sum[i]>r[i])return false;
    }
    return true;
}
int main(){
    cin>>n>>m;
    for(long long i=1;i<=n;i++)cin>>r[i];
    for(long long i=1;i<=m;i++)cin>>d[i]>>s[i]>>t[i];
    if(check(m)){
        cout<<0;
        return 0;
    }
    long long left=1,right=m;
    while(left<right){
        long long mid=(left+right)/2;
        if(check(mid))left=mid+1;
        else right=mid;
    }
    cout<<-1<<endl<<left;
    return 0;
}
